import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'cards' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    if (mode === 'cards') {
      alert("Please use the 'Flashcards' tab in the main menu for this mode.");
      return; 
    }

    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">BANK</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Mistakes</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                   </button>

                   {/* Cards Card (Visual only, redirects) */}
                   <button 
                     onClick={() => setMode('cards')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'cards' ? 'border-emerald-500 bg-emerald-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Layers size={24} className={mode === 'cards' ? 'text-emerald-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Cards</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">STUDY</span>
                   </button>
                </div>

                {/* Question Bank Select */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Question Bank</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className="w-full p-4 bg-white border border-slate-200 rounded-xl flex justify-between items-center shadow-sm hover:border-rose-200 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="text-rose-500"><FilterIcon size={18}/></div> 
                         <span className="font-bold text-sm text-slate-700">
                           {selectedCategories.length === 0 ? "All Topics" : `${selectedCategories.length} Chapters Selected`}
                         </span>
                      </div>
                      <ChevronRight size={18} className="text-slate-400" />
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-transform active:scale-95 disabled:opacity-50 disabled:shadow-none"
                >
                   {maxQuestions > 0 ? 'Start Session' : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[80vh] sm:h-auto rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-4 rounded-xl flex items-center justify-between transition-all border-2 ${isSelected ? 'border-rose-500 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`text-xs font-bold text-left ${isSelected ? 'text-rose-900' : 'text-slate-600'}`}>{cat}</span>
                          <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-rose-500 bg-rose-500' : 'border-slate-300'}`}>
                             {isSelected && <Check size={12} className="text-white" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800">
                      Apply Selection ({selectedCategories.length || 'All'})
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) statusColor = "bg-slate-100 border-slate-300 text-slate-700";

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20">
             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> Anatomy Final
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' && (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className="absolute top-0 left-0 w-full h-1.5 bg-blue-600 rounded-t-[1.5rem]"></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       return (
                         <button 
                          key={i} 
                          onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} 
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${isSelected ? 'border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500' : 'border-slate-100 hover:border-slate-300 hover:bg-slate-50'}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm ${isSelected ? 'border-blue-500 bg-blue-600 text-white' : 'border-slate-200 text-slate-300 bg-white group-hover:border-slate-300'}`}>
                              {String.fromCharCode(65 + i)}
                           </div>
                           <span className={`text-base font-medium leading-snug ${isSelected ? 'text-blue-900' : 'text-slate-700'}`} dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>
                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Submit' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

// Helper Icon for Filter
const FilterIcon = ({size} : {size: number}) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>
)

export default Quiz;

import React, { useState, useMemo } from 'react';
import { Question } from '../types';
import { 
  Clock, Zap, AlertTriangle, CheckCircle, XCircle, 
  ChevronRight, RotateCcw, Trophy, Activity, Filter, X
} from 'lucide-react';

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader: (visible: boolean) => void;
}

type QuizMode = 'setup' | 'exam' | 'practice' | 'mistakes';

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader }) => {
  const [mode, setMode] = useState<QuizMode>('setup');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [questionCount, setQuestionCount] = useState(10);
  const [activeQuestions, setActiveQuestions] = useState<Question[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Categories derived from data
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const handleStartQuiz = (selectedMode: QuizMode) => {
    let pool = data;

    if (selectedMode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
      if (pool.length === 0) {
        alert("No mistakes recorded yet!");
        return;
      }
    } else if (selectedCategory !== 'All') {
      pool = pool.filter(q => q.category === selectedCategory);
    }

    // Shuffle and slice
    const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, selectedMode === 'mistakes' ? pool.length : questionCount);

    if (shuffled.length === 0) {
      alert("No questions available for this selection.");
      return;
    }

    setActiveQuestions(shuffled);
    setCurrentIndex(0);
    setScore(0);
    setShowResult(false);
    setMode(selectedMode);
    toggleHeader(false);
    setIsAnswered(false);
    setSelectedOption(null);
  };

  const handleOptionSelect = (option: string) => {
    if (isAnswered) return;
    setSelectedOption(option);

    if (mode === 'practice' || mode === 'mistakes') {
        const currentQ = activeQuestions[currentIndex];
        const isCorrect = option === currentQ.answerText;
        if (isCorrect) {
            setScore(s => s + 1);
            if (mode === 'mistakes') {
               // Optional: remove from mistakes if corrected?
               // const newVault = mistakesVault.filter(id => id !== currentQ.id);
               // setMistakesVault(newVault);
               // localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(newVault));
            }
        } else {
            // Add to mistakes
            if (!mistakesVault.includes(currentQ.id)) {
                const newVault = [...mistakesVault, currentQ.id];
                setMistakesVault(newVault);
                localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(newVault));
            }
        }
        setIsAnswered(true);
    }
  };

  const handleNext = () => {
    if (currentIndex < activeQuestions.length - 1) {
        setCurrentIndex(prev => prev + 1);
        setIsAnswered(false);
        setSelectedOption(null);
    } else {
        finishQuiz();
    }
  };

  const finishQuiz = () => {
      setShowResult(true);
      toggleHeader(true);
  };

  const submitExamAnswer = () => {
      if (!selectedOption) return;
      const currentQ = activeQuestions[currentIndex];
      if (selectedOption === currentQ.answerText) {
          setScore(s => s + 1);
      } else {
           if (!mistakesVault.includes(currentQ.id)) {
                const newVault = [...mistakesVault, currentQ.id];
                setMistakesVault(newVault);
                localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(newVault));
            }
      }
      handleNext();
  }

  // Setup View
  if (mode === 'setup') {
      return (
        <div className="max-w-2xl mx-auto w-full pb-32">
             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   <button 
                     onClick={() => handleStartQuiz('exam')}
                     className="p-6 rounded-3xl border-2 border-slate-100 bg-white hover:border-rose-500 hover:shadow-xl transition-all group flex flex-col items-center gap-4 text-center"
                   >
                      <div className="w-16 h-16 bg-rose-50 rounded-2xl flex items-center justify-center text-rose-600 group-hover:scale-110 transition-transform">
                        <Clock size={32} />
                      </div>
                      <div>
                        <h3 className="font-black text-slate-800 text-lg">Examination</h3>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Timed • No Hints</p>
                      </div>
                   </button>

                   <button 
                     onClick={() => handleStartQuiz('practice')}
                     className="p-6 rounded-3xl border-2 border-slate-100 bg-white hover:border-blue-500 hover:shadow-xl transition-all group flex flex-col items-center gap-4 text-center"
                   >
                      <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 group-hover:scale-110 transition-transform">
                        <Zap size={32} />
                      </div>
                      <div>
                        <h3 className="font-black text-slate-800 text-lg">Practice Mode</h3>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Instant Feedback</p>
                      </div>
                   </button>

                   <button 
                     onClick={() => handleStartQuiz('mistakes')}
                     className="col-span-1 md:col-span-2 p-6 rounded-3xl border-2 border-amber-100 bg-amber-50/50 hover:border-amber-500 hover:bg-amber-50 transition-all group flex items-center justify-between px-8"
                   >
                      <div className="flex items-center gap-6">
                        <div className="w-14 h-14 bg-amber-100 rounded-2xl flex items-center justify-center text-amber-600 group-hover:rotate-12 transition-transform">
                            <AlertTriangle size={28} />
                        </div>
                        <div className="text-left">
                            <h3 className="font-black text-slate-800 text-lg">Mistakes Review</h3>
                            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-1">Target Weaknesses</p>
                        </div>
                      </div>
                      <div className="text-2xl font-black text-amber-600">{mistakesVault.length}</div>
                   </button>
                </div>

                {/* Settings */}
                <div className="bg-white rounded-[2rem] border border-slate-200 p-8 space-y-8 shadow-sm">
                    <div className="space-y-4">
                        <label className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest">
                            <Filter size={14} /> Question Source
                        </label>
                        <select 
                            value={selectedCategory} 
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className="w-full p-4 rounded-xl bg-slate-50 border border-slate-200 font-bold text-slate-700 outline-none focus:border-rose-500 transition-colors"
                        >
                            {categories.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                    </div>

                    <div className="space-y-4">
                        <label className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest">
                            <Activity size={14} /> Session Length
                        </label>
                        <div className="flex gap-3">
                            {[10, 25, 50, 100].map(num => (
                                <button 
                                    key={num}
                                    onClick={() => setQuestionCount(num)}
                                    className={`flex-1 py-3 rounded-xl font-bold text-sm transition-all border-2 ${questionCount === num ? 'border-rose-500 bg-rose-50 text-rose-700' : 'border-slate-100 bg-white text-slate-500 hover:border-slate-200'}`}
                                >
                                    {num}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
             </div>
        </div>
      );
  }

  // Active Quiz View
  if (!showResult && activeQuestions.length > 0) {
      const currentQ = activeQuestions[currentIndex];
      const isPractice = mode === 'practice' || mode === 'mistakes';

      return (
          <div className="flex flex-col h-full bg-slate-50">
              {/* Quiz Header */}
              <div className="px-6 py-6 bg-white border-b border-slate-100 flex items-center justify-between sticky top-0 z-10">
                  <div className="flex items-center gap-4">
                      <button onClick={() => { setMode('setup'); toggleHeader(true); }} className="p-2 bg-slate-50 rounded-xl hover:bg-slate-100 text-slate-400"><X size={20} /></button>
                      <div>
                          <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Question {currentIndex + 1} of {activeQuestions.length}</div>
                          <div className="h-1.5 w-32 bg-slate-100 rounded-full mt-1 overflow-hidden">
                              <div className="h-full bg-rose-500 transition-all duration-300" style={{ width: `${((currentIndex + 1) / activeQuestions.length) * 100}%` }}></div>
                          </div>
                      </div>
                  </div>
                  {isPractice && (
                      <div className="text-right">
                          <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Current Score</div>
                          <div className="text-lg font-black text-emerald-500">{score}</div>
                      </div>
                  )}
              </div>

              {/* Question Area */}
              <div className="flex-1 overflow-y-auto p-6 md:p-8 custom-scrollbar">
                  <div className="max-w-3xl mx-auto space-y-8">
                      {currentQ.questionImage && (
                          <div className="w-full max-h-64 flex justify-center bg-white rounded-3xl p-4 border border-slate-100 shadow-sm">
                              <img src={currentQ.questionImage} className="h-full object-contain rounded-xl" alt="Diagram" />
                          </div>
                      )}

                      <h2 className="text-xl md:text-2xl font-black text-slate-800 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.questionText }} />

                      <div className="grid gap-3">
                          {currentQ.options?.map((opt, i) => {
                              let stateStyles = "bg-white border-slate-200 text-slate-600 hover:border-blue-300 hover:bg-blue-50";
                              let icon = null;

                              if (isPractice && isAnswered) {
                                  if (opt === currentQ.answerText) {
                                      stateStyles = "bg-emerald-50 border-emerald-500 text-emerald-700 shadow-emerald-100";
                                      icon = <CheckCircle size={20} className="text-emerald-500" />;
                                  } else if (opt === selectedOption && opt !== currentQ.answerText) {
                                      stateStyles = "bg-red-50 border-red-500 text-red-700 shadow-red-100 opacity-60";
                                      icon = <XCircle size={20} className="text-red-500" />;
                                  } else {
                                      stateStyles = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                                  }
                              } else if (selectedOption === opt) {
                                  stateStyles = "bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200";
                              }

                              return (
                                  <button
                                      key={i}
                                      onClick={() => !isAnswered && !isPractice ? setSelectedOption(opt) : handleOptionSelect(opt)}
                                      disabled={isPractice && isAnswered}
                                      className={`w-full p-5 rounded-2xl border-2 font-bold text-left text-base md:text-lg transition-all flex items-center justify-between shadow-sm ${stateStyles}`}
                                  >
                                      <span dangerouslySetInnerHTML={{ __html: opt }} />
                                      {icon}
                                  </button>
                              );
                          })}
                      </div>

                      {/* Explanation (Practice Mode) */}
                      {isPractice && isAnswered && (
                          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                              <div className="bg-blue-50/50 border border-blue-100 rounded-2xl p-6 space-y-2">
                                  <div className="flex items-center gap-2 text-xs font-black text-blue-400 uppercase tracking-widest">
                                      <Zap size={14} /> Explanation
                                  </div>
                                  <p className="text-slate-700 font-medium leading-relaxed italic">
                                      {currentQ.explanation || "No detailed explanation available for this record."}
                                  </p>
                              </div>
                              <button 
                                  onClick={handleNext}
                                  className="w-full mt-6 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-rose-600 transition-all shadow-xl flex items-center justify-center gap-2"
                              >
                                  Next Record <ChevronRight size={18} />
                              </button>
                          </div>
                      )}

                      {/* Exam Mode Navigation */}
                      {!isPractice && (
                          <button 
                              onClick={submitExamAnswer}
                              disabled={!selectedOption}
                              className="w-full mt-8 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-blue-600 transition-all shadow-xl disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                              {currentIndex === activeQuestions.length - 1 ? 'Submit Exam' : 'Next Question'}
                          </button>
                      )}
                  </div>
              </div>
          </div>
      );
  }

  // Results View
  if (showResult) {
      const percentage = Math.round((score / activeQuestions.length) * 100);
      let grade = 'F';
      let color = 'text-red-500';
      if (percentage >= 90) { grade = 'A'; color = 'text-emerald-500'; }
      else if (percentage >= 80) { grade = 'B'; color = 'text-blue-500'; }
      else if (percentage >= 70) { grade = 'C'; color = 'text-amber-500'; }
      else if (percentage >= 60) { grade = 'D'; color = 'text-orange-500'; }

      return (
          <div className="max-w-2xl mx-auto p-8 text-center space-y-10 animate-in zoom-in-95 duration-500">
              <div className="relative inline-block">
                  <Trophy size={80} className={`${color} drop-shadow-2xl`} />
                  <div className={`absolute -top-2 -right-4 w-12 h-12 bg-slate-900 rounded-full flex items-center justify-center text-white font-black text-xl border-4 border-white shadow-lg`}>
                      {grade}
                  </div>
              </div>

              <div className="space-y-2">
                  <h2 className="text-4xl font-black text-slate-800">Session Complete</h2>
                  <p className="text-slate-400 font-bold uppercase tracking-widest">Performance Report</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-lg">
                      <div className="text-4xl font-black text-slate-900">{score}</div>
                      <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Correct</div>
                  </div>
                  <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-lg">
                      <div className="text-4xl font-black text-slate-900">{percentage}%</div>
                      <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Accuracy</div>
                  </div>
              </div>

              <button 
                  onClick={() => { setMode('setup'); toggleHeader(true); }}
                  className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-rose-600 transition-all shadow-xl flex items-center justify-center gap-3 mx-auto"
              >
                  <RotateCcw size={18} /> Return to Dashboard
              </button>
          </div>
      );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">BANK</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`col-span-2 p-4 rounded-2xl border-2 transition-all flex flex-row items-center justify-center gap-3 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <div className="flex flex-col items-start">
                        <span className="font-bold text-slate-800 text-sm">Mistakes Review</span>
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                      </div>
                   </button>
                </div>

                {/* Question Bank Select */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Question Bank</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className="w-full p-4 bg-white border border-slate-200 rounded-xl flex justify-between items-center shadow-sm hover:border-rose-200 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="text-rose-500"><FilterIcon size={18}/></div> 
                         <span className="font-bold text-sm text-slate-700">
                           {selectedCategories.length === 0 ? "All Topics" : `${selectedCategories.length} Chapters Selected`}
                         </span>
                      </div>
                      <ChevronRight size={18} className="text-slate-400" />
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-transform active:scale-95 disabled:opacity-50 disabled:shadow-none"
                >
                   {maxQuestions > 0 ? 'Start Session' : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[80vh] sm:h-auto rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-4 rounded-xl flex items-center justify-between transition-all border-2 ${isSelected ? 'border-rose-500 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`text-xs font-bold text-left ${isSelected ? 'text-rose-900' : 'text-slate-600'}`}>{cat}</span>
                          <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-rose-500 bg-rose-500' : 'border-slate-300'}`}>
                             {isSelected && <Check size={12} className="text-white" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800">
                      Apply Selection ({selectedCategories.length || 'All'})
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            // In Practice mode, show Green for correct, Red for incorrect
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            // In Exam mode, just show answered state
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
              )}
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20">
             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> {isPracticeMode ? (mode === 'mistakes' ? 'Mistakes Review' : 'Practice Mode') : 'Anatomy Final'}
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' ? (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                ) : (
                    // In Practice mode, show score instead of timer
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                            <CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}
                        </div>
                        <div className="flex items-center gap-1.5 text-xs font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg border border-rose-100">
                            <XCircle size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}
                        </div>
                    </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className={`absolute top-0 left-0 w-full h-1.5 rounded-t-[1.5rem] ${isPracticeMode ? 'bg-indigo-500' : 'bg-blue-600'}`}></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       const isAnswered = !!currentQ.userAnswer;

                       let containerClasses = "bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50 text-slate-700";
                       let badgeClasses = "border-slate-200 text-slate-300 bg-white group-hover:border-slate-300";

                       if (isPracticeMode && isAnswered) {
                           // PRACTICE MODE LOGIC: Immediate Feedback
                           if (opt === currentQ.correctOption) {
                               // Correct Answer: Always Green
                               containerClasses = "bg-emerald-50 border-emerald-500 text-emerald-800 shadow-sm";
                               badgeClasses = "border-emerald-500 bg-emerald-500 text-white";
                           } else if (isSelected && opt !== currentQ.correctOption) {
                               // Wrong Selection: Red
                               containerClasses = "bg-rose-50 border-rose-500 text-rose-800 shadow-sm opacity-100";
                               badgeClasses = "border-rose-500 bg-rose-500 text-white";
                           } else {
                               // Other irrelevant options: Fade out
                               containerClasses = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                           }
                       } else {
                           // EXAM MODE LOGIC: Standard Blue Selection
                           if (isSelected) {
                               containerClasses = "border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500 text-blue-900";
                               badgeClasses = "border-blue-500 bg-blue-600 text-white";
                           }
                       }

                       return (
                         <button 
                          key={i} 
                          onClick={() => {
                              if (isPracticeMode && isAnswered) return; // Prevent changing answer in practice mode
                              setQuestions(prev => { 
                                  const c = [...prev]; 
                                  c[currentQIndex].userAnswer = opt; 
                                  return c; 
                              });
                          }} 
                          disabled={isPracticeMode && isAnswered}
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${containerClasses}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm transition-colors ${badgeClasses}`}>
                              {isPracticeMode && isAnswered && opt === currentQ.correctOption ? <Check size={16} strokeWidth={4} /> : 
                               isPracticeMode && isAnswered && isSelected && opt !== currentQ.correctOption ? <X size={16} strokeWidth={4} /> :
                               String.fromCharCode(65 + i)}
                           </div>
                           <span className="text-base font-medium leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>

                  {/* Immediate Explanation in Practice Mode */}
                  {isPracticeMode && currentQ.userAnswer && (
                      <div className="mt-8 pt-8 border-t border-slate-100 animate-in slide-in-from-bottom-2 fade-in duration-500">
                          <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-slate-50 border-slate-300'}`}>
                              <div className="flex items-center gap-3 mb-3">
                                  <div className={`p-2 rounded-lg ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                                      <Zap size={18} fill="currentColor" />
                                  </div>
                                  <h4 className={`font-black uppercase tracking-widest text-xs ${currentQ.userAnswer === currentQ.correctOption ? 'text-emerald-700' : 'text-slate-600'}`}>
                                      {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                  </h4>
                              </div>
                              <p className="text-slate-700 font-medium leading-relaxed">
                                  {currentQ.data.explanation || "No detailed explanation is available for this record."}
                              </p>
                          </div>
                      </div>
                  )}

                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Finish' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

// Helper Icon for Filter
const FilterIcon = ({size} : {size: number}) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>
)

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle,
  Play
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">BANK</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`col-span-2 p-4 rounded-2xl border-2 transition-all flex flex-row items-center justify-center gap-3 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <div className="flex flex-col items-start">
                        <span className="font-bold text-slate-800 text-sm">Mistakes Review</span>
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                      </div>
                   </button>
                </div>

                {/* Question Bank Select */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Question Bank</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className="w-full p-4 bg-white border border-slate-200 rounded-xl flex justify-between items-center shadow-sm hover:border-rose-200 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="text-rose-500"><FilterIcon size={18}/></div> 
                         <span className="font-bold text-sm text-slate-700">
                           {selectedCategories.length === 0 ? "All Topics" : `${selectedCategories.length} Chapters Selected`}
                         </span>
                      </div>
                      <ChevronRight size={18} className="text-slate-400" />
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-all active:scale-95 disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 group"
                >
                   {maxQuestions > 0 ? (
                     <>
                        Start Session <Play size={20} fill="currentColor" className="group-hover:translate-x-1 transition-transform" />
                     </>
                   ) : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[80vh] sm:h-auto rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-4 rounded-xl flex items-center justify-between transition-all border-2 ${isSelected ? 'border-rose-500 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`text-xs font-bold text-left ${isSelected ? 'text-rose-900' : 'text-slate-600'}`}>{cat}</span>
                          <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-rose-500 bg-rose-500' : 'border-slate-300'}`}>
                             {isSelected && <Check size={12} className="text-white" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800">
                      Apply Selection ({selectedCategories.length || 'All'})
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            // In Practice mode, show Green for correct, Red for incorrect
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            // In Exam mode, just show answered state
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
              )}
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20 relative">
             {/* Progress Bar (The Step Visualization) */}
             <div className="absolute bottom-0 left-0 w-full h-1 bg-slate-100">
                <div 
                    className="h-full bg-rose-500 transition-all duration-500 ease-out"
                    style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                />
             </div>

             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> {isPracticeMode ? (mode === 'mistakes' ? 'Mistakes Review' : 'Practice Mode') : 'Anatomy Final'}
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' ? (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                ) : (
                    // In Practice mode, show score instead of timer
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                            <CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}
                        </div>
                        <div className="flex items-center gap-1.5 text-xs font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg border border-rose-100">
                            <XCircle size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}
                        </div>
                    </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className={`absolute top-0 left-0 w-full h-1.5 rounded-t-[1.5rem] ${isPracticeMode ? 'bg-indigo-500' : 'bg-blue-600'}`}></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       const isAnswered = !!currentQ.userAnswer;

                       let containerClasses = "bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50 text-slate-700";
                       let badgeClasses = "border-slate-200 text-slate-300 bg-white group-hover:border-slate-300";

                       if (isPracticeMode && isAnswered) {
                           // PRACTICE MODE LOGIC: Immediate Feedback
                           if (opt === currentQ.correctOption) {
                               // Correct Answer: Always Green
                               containerClasses = "bg-emerald-50 border-emerald-500 text-emerald-800 shadow-sm";
                               badgeClasses = "border-emerald-500 bg-emerald-500 text-white";
                           } else if (isSelected && opt !== currentQ.correctOption) {
                               // Wrong Selection: Red
                               containerClasses = "bg-rose-50 border-rose-500 text-rose-800 shadow-sm opacity-100";
                               badgeClasses = "border-rose-500 bg-rose-500 text-white";
                           } else {
                               // Other irrelevant options: Fade out
                               containerClasses = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                           }
                       } else {
                           // EXAM MODE LOGIC: Standard Blue Selection
                           if (isSelected) {
                               containerClasses = "border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500 text-blue-900";
                               badgeClasses = "border-blue-500 bg-blue-600 text-white";
                           }
                       }

                       return (
                         <button 
                          key={i} 
                          onClick={() => {
                              if (isPracticeMode && isAnswered) return; // Prevent changing answer in practice mode
                              setQuestions(prev => { 
                                  const c = [...prev]; 
                                  c[currentQIndex].userAnswer = opt; 
                                  return c; 
                              });
                          }} 
                          disabled={isPracticeMode && isAnswered}
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${containerClasses}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm transition-colors ${badgeClasses}`}>
                              {isPracticeMode && isAnswered && opt === currentQ.correctOption ? <Check size={16} strokeWidth={4} /> : 
                               isPracticeMode && isAnswered && isSelected && opt !== currentQ.correctOption ? <X size={16} strokeWidth={4} /> :
                               String.fromCharCode(65 + i)}
                           </div>
                           <span className="text-base font-medium leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>

                  {/* Immediate Explanation in Practice Mode */}
                  {isPracticeMode && currentQ.userAnswer && (
                      <div className="mt-8 pt-8 border-t border-slate-100 animate-in slide-in-from-bottom-2 fade-in duration-500">
                          <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-slate-50 border-slate-300'}`}>
                              <div className="flex items-center gap-3 mb-3">
                                  <div className={`p-2 rounded-lg ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                                      <Zap size={18} fill="currentColor" />
                                  </div>
                                  <h4 className={`font-black uppercase tracking-widest text-xs ${currentQ.userAnswer === currentQ.correctOption ? 'text-emerald-700' : 'text-slate-600'}`}>
                                      {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                  </h4>
                              </div>
                              <p className="text-slate-700 font-medium leading-relaxed">
                                  {currentQ.data.explanation || "No detailed explanation is available for this record."}
                              </p>
                          </div>
                      </div>
                  )}

                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Finish' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

// Helper Icon for Filter
const FilterIcon = ({size} : {size: number}) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>
)

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle,
  Play, BarChart3
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">TOTAL QUESTIONS</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`col-span-2 p-4 rounded-2xl border-2 transition-all flex flex-row items-center justify-center gap-3 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <div className="flex flex-col items-start">
                        <span className="font-bold text-slate-800 text-sm">Mistakes Review</span>
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                      </div>
                   </button>
                </div>

                {/* Question Bank Select */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Question Bank</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className="w-full p-4 bg-white border border-slate-200 rounded-xl flex justify-between items-center shadow-sm hover:border-rose-200 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="text-rose-500"><FilterIcon size={18}/></div> 
                         <span className="font-bold text-sm text-slate-700">
                           {selectedCategories.length === 0 ? "All Topics" : `${selectedCategories.length} Chapters Selected`}
                         </span>
                      </div>
                      <ChevronRight size={18} className="text-slate-400" />
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-all active:scale-95 disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 group"
                >
                   {maxQuestions > 0 ? (
                     <>
                        Start Session <Play size={20} fill="currentColor" className="group-hover:translate-x-1 transition-transform" />
                     </>
                   ) : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[80vh] sm:h-auto rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-4 rounded-xl flex items-center justify-between transition-all border-2 ${isSelected ? 'border-rose-500 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`text-xs font-bold text-left ${isSelected ? 'text-rose-900' : 'text-slate-600'}`}>{cat}</span>
                          <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-rose-500 bg-rose-500' : 'border-slate-300'}`}>
                             {isSelected && <Check size={12} className="text-white" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800">
                      Apply Selection ({selectedCategories.length || 'All'})
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            // In Practice mode, show Green for correct, Red for incorrect
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            // In Exam mode, just show answered state
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
              )}
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar with Progress */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20 relative overflow-hidden">

             {/* Progress Bar (The Step Visualization) */}
             <div className="absolute bottom-0 left-0 w-full h-1.5 bg-slate-100">
                <div 
                    className="h-full bg-rose-500 transition-all duration-500 ease-out relative"
                    style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                >
                    <div className="absolute right-0 top-0 bottom-0 w-2 bg-white/50 blur-[2px]"></div>
                </div>
             </div>

             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> {isPracticeMode ? (mode === 'mistakes' ? 'Mistakes Review' : 'Practice Mode') : 'Anatomy Final'}
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' ? (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                ) : (
                    // In Practice mode, show score instead of timer
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                            <CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}
                        </div>
                        <div className="flex items-center gap-1.5 text-xs font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg border border-rose-100">
                            <XCircle size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}
                        </div>
                    </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className={`absolute top-0 left-0 w-full h-1.5 rounded-t-[1.5rem] ${isPracticeMode ? 'bg-indigo-500' : 'bg-blue-600'}`}></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       const isAnswered = !!currentQ.userAnswer;

                       let containerClasses = "bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50 text-slate-700";
                       let badgeClasses = "border-slate-200 text-slate-300 bg-white group-hover:border-slate-300";

                       if (isPracticeMode && isAnswered) {
                           // PRACTICE MODE LOGIC: Immediate Feedback
                           if (opt === currentQ.correctOption) {
                               // Correct Answer: Always Green
                               containerClasses = "bg-emerald-50 border-emerald-500 text-emerald-800 shadow-sm";
                               badgeClasses = "border-emerald-500 bg-emerald-500 text-white";
                           } else if (isSelected && opt !== currentQ.correctOption) {
                               // Wrong Selection: Red
                               containerClasses = "bg-rose-50 border-rose-500 text-rose-800 shadow-sm opacity-100";
                               badgeClasses = "border-rose-500 bg-rose-500 text-white";
                           } else {
                               // Other irrelevant options: Fade out
                               containerClasses = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                           }
                       } else {
                           // EXAM MODE LOGIC: Standard Blue Selection
                           if (isSelected) {
                               containerClasses = "border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500 text-blue-900";
                               badgeClasses = "border-blue-500 bg-blue-600 text-white";
                           }
                       }

                       return (
                         <button 
                          key={i} 
                          onClick={() => {
                              if (isPracticeMode && isAnswered) return; // Prevent changing answer in practice mode
                              setQuestions(prev => { 
                                  const c = [...prev]; 
                                  c[currentQIndex].userAnswer = opt; 
                                  return c; 
                              });
                          }} 
                          disabled={isPracticeMode && isAnswered}
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${containerClasses}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm transition-colors ${badgeClasses}`}>
                              {isPracticeMode && isAnswered && opt === currentQ.correctOption ? <Check size={16} strokeWidth={4} /> : 
                               isPracticeMode && isAnswered && isSelected && opt !== currentQ.correctOption ? <X size={16} strokeWidth={4} /> :
                               String.fromCharCode(65 + i)}
                           </div>
                           <span className="text-base font-medium leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>

                  {/* Immediate Explanation in Practice Mode */}
                  {isPracticeMode && currentQ.userAnswer && (
                      <div className="mt-8 pt-8 border-t border-slate-100 animate-in slide-in-from-bottom-2 fade-in duration-500">
                          <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-slate-50 border-slate-300'}`}>
                              <div className="flex items-center gap-3 mb-3">
                                  <div className={`p-2 rounded-lg ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                                      <Zap size={18} fill="currentColor" />
                                  </div>
                                  <h4 className={`font-black uppercase tracking-widest text-xs ${currentQ.userAnswer === currentQ.correctOption ? 'text-emerald-700' : 'text-slate-600'}`}>
                                      {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                  </h4>
                              </div>
                              <p className="text-slate-700 font-medium leading-relaxed">
                                  {currentQ.data.explanation || "No detailed explanation is available for this record."}
                              </p>
                          </div>
                      </div>
                  )}

                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Finish' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

// Helper Icon for Filter
const FilterIcon = ({size} : {size: number}) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>
)

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle,
  Play, BarChart3, Settings2
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">TOTAL QUESTIONS</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`col-span-2 p-4 rounded-2xl border-2 transition-all flex flex-row items-center justify-center gap-3 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <div className="flex flex-col items-start">
                        <span className="font-bold text-slate-800 text-sm">Mistakes Review</span>
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                      </div>
                   </button>
                </div>

                {/* Question Bank Select (Enhanced Button) */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Target Content</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className={`w-full p-5 rounded-2xl flex justify-between items-center shadow-md transition-all group border-2 ${selectedCategories.length > 0 ? 'bg-slate-900 border-slate-900 text-white' : 'bg-white border-slate-200 text-slate-700 hover:border-blue-300'}`}
                   >
                      <div className="flex items-center gap-4">
                         <div className={`p-3 rounded-xl ${selectedCategories.length > 0 ? 'bg-white/10' : 'bg-slate-100'}`}>
                            <Settings2 size={20} className={selectedCategories.length > 0 ? 'text-white' : 'text-slate-500'} />
                         </div>
                         <div className="flex flex-col items-start">
                            <span className="font-black text-sm uppercase tracking-wide">
                               {selectedCategories.length === 0 ? "All Chapters" : "Custom Selection"}
                            </span>
                            <span className={`text-[10px] font-bold uppercase tracking-widest ${selectedCategories.length > 0 ? 'text-slate-400' : 'text-slate-400'}`}>
                               {selectedCategories.length === 0 ? "Default: Full Bank" : `${selectedCategories.length} Topics Active`}
                            </span>
                         </div>
                      </div>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${selectedCategories.length > 0 ? 'border-white/20 bg-white/10' : 'border-slate-100 bg-slate-50'}`}>
                         <ChevronRight size={14} />
                      </div>
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-all active:scale-95 disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 group"
                >
                   {maxQuestions > 0 ? (
                     <>
                        Start Session <Play size={20} fill="currentColor" className="group-hover:translate-x-1 transition-transform" />
                     </>
                   ) : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal (Enhanced) */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[80vh] sm:h-auto rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-5 rounded-2xl flex items-center justify-between transition-all duration-200 border-2 group active:scale-[0.98] ${isSelected ? 'border-emerald-500 bg-emerald-50/50 shadow-sm' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`font-bold text-left leading-tight ${isSelected ? 'text-emerald-900' : 'text-slate-600'}`}>{cat}</span>

                          {/* Enhanced Checkbox */}
                          <div className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center transition-all duration-300 ${isSelected ? 'border-emerald-500 bg-emerald-500 scale-110' : 'border-slate-200 bg-slate-50 group-hover:border-slate-300'}`}>
                             {isSelected && <Check size={16} className="text-white animate-in zoom-in duration-200" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 shadow-lg">
                      Apply Selection ({selectedCategories.length || 'All'})
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            // In Practice mode, show Green for correct, Red for incorrect
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            // In Exam mode, just show answered state
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
              )}
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar with Progress */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20 relative overflow-hidden">

             {/* Progress Bar (The Step Visualization) */}
             <div className="absolute bottom-0 left-0 w-full h-1.5 bg-slate-100">
                <div 
                    className="h-full bg-rose-500 transition-all duration-500 ease-out relative"
                    style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                >
                    <div className="absolute right-0 top-0 bottom-0 w-2 bg-white/50 blur-[2px]"></div>
                </div>
             </div>

             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> {isPracticeMode ? (mode === 'mistakes' ? 'Mistakes Review' : 'Practice Mode') : 'Anatomy Final'}
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' ? (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                ) : (
                    // In Practice mode, show score instead of timer
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                            <CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}
                        </div>
                        <div className="flex items-center gap-1.5 text-xs font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg border border-rose-100">
                            <XCircle size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}
                        </div>
                    </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className={`absolute top-0 left-0 w-full h-1.5 rounded-t-[1.5rem] ${isPracticeMode ? 'bg-indigo-500' : 'bg-blue-600'}`}></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       const isAnswered = !!currentQ.userAnswer;

                       let containerClasses = "bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50 text-slate-700";
                       let badgeClasses = "border-slate-200 text-slate-300 bg-white group-hover:border-slate-300";

                       if (isPracticeMode && isAnswered) {
                           // PRACTICE MODE LOGIC: Immediate Feedback
                           if (opt === currentQ.correctOption) {
                               // Correct Answer: Always Green
                               containerClasses = "bg-emerald-50 border-emerald-500 text-emerald-800 shadow-sm";
                               badgeClasses = "border-emerald-500 bg-emerald-500 text-white";
                           } else if (isSelected && opt !== currentQ.correctOption) {
                               // Wrong Selection: Red
                               containerClasses = "bg-rose-50 border-rose-500 text-rose-800 shadow-sm opacity-100";
                               badgeClasses = "border-rose-500 bg-rose-500 text-white";
                           } else {
                               // Other irrelevant options: Fade out
                               containerClasses = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                           }
                       } else {
                           // EXAM MODE LOGIC: Standard Blue Selection
                           if (isSelected) {
                               containerClasses = "border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500 text-blue-900";
                               badgeClasses = "border-blue-500 bg-blue-600 text-white";
                           }
                       }

                       return (
                         <button 
                          key={i} 
                          onClick={() => {
                              if (isPracticeMode && isAnswered) return; // Prevent changing answer in practice mode
                              setQuestions(prev => { 
                                  const c = [...prev]; 
                                  c[currentQIndex].userAnswer = opt; 
                                  return c; 
                              });
                          }} 
                          disabled={isPracticeMode && isAnswered}
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${containerClasses}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm transition-colors ${badgeClasses}`}>
                              {isPracticeMode && isAnswered && opt === currentQ.correctOption ? <Check size={16} strokeWidth={4} /> : 
                               isPracticeMode && isAnswered && isSelected && opt !== currentQ.correctOption ? <X size={16} strokeWidth={4} /> :
                               String.fromCharCode(65 + i)}
                           </div>
                           <span className="text-base font-medium leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>

                  {/* Immediate Explanation in Practice Mode */}
                  {isPracticeMode && currentQ.userAnswer && (
                      <div className="mt-8 pt-8 border-t border-slate-100 animate-in slide-in-from-bottom-2 fade-in duration-500">
                          <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-slate-50 border-slate-300'}`}>
                              <div className="flex items-center gap-3 mb-3">
                                  <div className={`p-2 rounded-lg ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                                      <Zap size={18} fill="currentColor" />
                                  </div>
                                  <h4 className={`font-black uppercase tracking-widest text-xs ${currentQ.userAnswer === currentQ.correctOption ? 'text-emerald-700' : 'text-slate-600'}`}>
                                      {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                  </h4>
                              </div>
                              <p className="text-slate-700 font-medium leading-relaxed">
                                  {currentQ.data.explanation || "No detailed explanation is available for this record."}
                              </p>
                          </div>
                      </div>
                  )}

                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Finish' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

// Helper Icon for Filter
const FilterIcon = ({size} : {size: number}) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>
)

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle,
  Play, BarChart3, Settings2
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">TOTAL QUESTIONS</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`col-span-2 p-4 rounded-2xl border-2 transition-all flex flex-row items-center justify-center gap-3 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <div className="flex flex-col items-start">
                        <span className="font-bold text-slate-800 text-sm">Mistakes Review</span>
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                      </div>
                   </button>
                </div>

                {/* Question Bank Select (Enhanced Button) */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Target Content</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className={`w-full p-5 rounded-2xl flex justify-between items-center shadow-md transition-all group border-2 ${selectedCategories.length > 0 ? 'bg-slate-900 border-slate-900 text-white' : 'bg-white border-slate-200 text-slate-700 hover:border-blue-300'}`}
                   >
                      <div className="flex items-center gap-4">
                         <div className={`p-3 rounded-xl ${selectedCategories.length > 0 ? 'bg-white/10' : 'bg-slate-100'}`}>
                            <Settings2 size={20} className={selectedCategories.length > 0 ? 'text-white' : 'text-slate-500'} />
                         </div>
                         <div className="flex flex-col items-start">
                            <span className="font-black text-sm uppercase tracking-wide">
                               {selectedCategories.length === 0 ? "All Chapters" : "Custom Selection"}
                            </span>
                            <span className={`text-[10px] font-bold uppercase tracking-widest ${selectedCategories.length > 0 ? 'text-slate-400' : 'text-slate-400'}`}>
                               {selectedCategories.length === 0 ? "Default: Full Bank" : `${selectedCategories.length} Topics Active`}
                            </span>
                         </div>
                      </div>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${selectedCategories.length > 0 ? 'border-white/20 bg-white/10' : 'border-slate-100 bg-slate-50'}`}>
                         <ChevronRight size={14} />
                      </div>
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-all active:scale-95 disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 group"
                >
                   {maxQuestions > 0 ? (
                     <>
                        Start Session <Play size={20} fill="currentColor" className="group-hover:translate-x-1 transition-transform" />
                     </>
                   ) : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal (Enhanced) */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[85vh] sm:h-auto max-h-[85vh] rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-5 rounded-2xl flex items-center justify-between transition-all duration-200 border-2 group active:scale-[0.98] ${isSelected ? 'border-emerald-500 bg-emerald-50/50 shadow-sm' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`font-bold text-left leading-tight ${isSelected ? 'text-emerald-900' : 'text-slate-600'}`}>{cat}</span>

                          {/* Enhanced Checkbox */}
                          <div className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center transition-all duration-300 ${isSelected ? 'border-emerald-500 bg-emerald-500 scale-110' : 'border-slate-200 bg-slate-50 group-hover:border-slate-300'}`}>
                             {isSelected && <Check size={16} className="text-white animate-in zoom-in duration-200" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100 bg-white shrink-0 pb-safe">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-emerald-700 shadow-xl shadow-emerald-200 flex items-center justify-center gap-3 transition-transform active:scale-95">
                      <CheckCircle2 size={20} strokeWidth={3} />
                      <span>CONFIRM</span>
                      <span className="bg-emerald-500/50 px-2 py-0.5 rounded text-xs">
                        {selectedCategories.length > 0 ? selectedCategories.length : 'All'}
                      </span>
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            // In Practice mode, show Green for correct, Red for incorrect
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            // In Exam mode, just show answered state
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
              )}
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar with Progress */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20 relative overflow-hidden">

             {/* Progress Bar (The Step Visualization) */}
             <div className="absolute bottom-0 left-0 w-full h-1.5 bg-slate-100">
                <div 
                    className="h-full bg-rose-500 transition-all duration-500 ease-out relative"
                    style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                >
                    <div className="absolute right-0 top-0 bottom-0 w-2 bg-white/50 blur-[2px]"></div>
                </div>
             </div>

             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> {isPracticeMode ? (mode === 'mistakes' ? 'Mistakes Review' : 'Practice Mode') : 'Anatomy Final'}
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' ? (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                ) : (
                    // In Practice mode, show score instead of timer
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                            <CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}
                        </div>
                        <div className="flex items-center gap-1.5 text-xs font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg border border-rose-100">
                            <XCircle size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}
                        </div>
                    </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className={`absolute top-0 left-0 w-full h-1.5 rounded-t-[1.5rem] ${isPracticeMode ? 'bg-indigo-500' : 'bg-blue-600'}`}></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       const isAnswered = !!currentQ.userAnswer;

                       let containerClasses = "bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50 text-slate-700";
                       let badgeClasses = "border-slate-200 text-slate-300 bg-white group-hover:border-slate-300";

                       if (isPracticeMode && isAnswered) {
                           // PRACTICE MODE LOGIC: Immediate Feedback
                           if (opt === currentQ.correctOption) {
                               // Correct Answer: Always Green
                               containerClasses = "bg-emerald-50 border-emerald-500 text-emerald-800 shadow-sm";
                               badgeClasses = "border-emerald-500 bg-emerald-500 text-white";
                           } else if (isSelected && opt !== currentQ.correctOption) {
                               // Wrong Selection: Red
                               containerClasses = "bg-rose-50 border-rose-500 text-rose-800 shadow-sm opacity-100";
                               badgeClasses = "border-rose-500 bg-rose-500 text-white";
                           } else {
                               // Other irrelevant options: Fade out
                               containerClasses = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                           }
                       } else {
                           // EXAM MODE LOGIC: Standard Blue Selection
                           if (isSelected) {
                               containerClasses = "border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500 text-blue-900";
                               badgeClasses = "border-blue-500 bg-blue-600 text-white";
                           }
                       }

                       return (
                         <button 
                          key={i} 
                          onClick={() => {
                              if (isPracticeMode && isAnswered) return; // Prevent changing answer in practice mode
                              setQuestions(prev => { 
                                  const c = [...prev]; 
                                  c[currentQIndex].userAnswer = opt; 
                                  return c; 
                              });
                          }} 
                          disabled={isPracticeMode && isAnswered}
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${containerClasses}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm transition-colors ${badgeClasses}`}>
                              {isPracticeMode && isAnswered && opt === currentQ.correctOption ? <Check size={16} strokeWidth={4} /> : 
                               isPracticeMode && isAnswered && isSelected && opt !== currentQ.correctOption ? <X size={16} strokeWidth={4} /> :
                               String.fromCharCode(65 + i)}
                           </div>
                           <span className="text-base font-medium leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>

                  {/* Immediate Explanation in Practice Mode */}
                  {isPracticeMode && currentQ.userAnswer && (
                      <div className="mt-8 pt-8 border-t border-slate-100 animate-in slide-in-from-bottom-2 fade-in duration-500">
                          <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-slate-50 border-slate-300'}`}>
                              <div className="flex items-center gap-3 mb-3">
                                  <div className={`p-2 rounded-lg ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                                      <Zap size={18} fill="currentColor" />
                                  </div>
                                  <h4 className={`font-black uppercase tracking-widest text-xs ${currentQ.userAnswer === currentQ.correctOption ? 'text-emerald-700' : 'text-slate-600'}`}>
                                      {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                  </h4>
                              </div>
                              <p className="text-slate-700 font-medium leading-relaxed">
                                  {currentQ.data.explanation || "No detailed explanation is available for this record."}
                              </p>
                          </div>
                      </div>
                  )}

                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Finish' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

// Helper Icon for Filter
const FilterIcon = ({size} : {size: number}) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>
)

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle,
  Play, BarChart3, Settings2
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    // Filter by Mistakes if in Mistakes Mode
    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice/Mistakes = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleRetakeMistakes = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.data);
    if (wrongOnes.length === 0) return;

    const preparedQuestions = prepareQuestions(wrongOnes);

    // Always shuffle retakes to prevent pattern memory
    const shuffled = preparedQuestions.sort(() => Math.random() - 0.5);

    setQuestions(shuffled);
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;

    if (mode === 'mistakes') {
      filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    }

    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">TOTAL QUESTIONS</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="grid grid-cols-2 gap-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Mistakes Card */}
                   <button 
                     onClick={() => setMode('mistakes')}
                     className={`col-span-2 p-4 rounded-2xl border-2 transition-all flex flex-row items-center justify-center gap-3 ${mode === 'mistakes' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <AlertTriangle size={24} className={mode === 'mistakes' ? 'text-amber-600' : 'text-slate-400'} />
                      <div className="flex flex-col items-start">
                        <span className="font-bold text-slate-800 text-sm">Mistakes Review</span>
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{mistakesVault.length} ERRORS</span>
                      </div>
                   </button>
                </div>

                {/* Question Bank Select (Enhanced Button) */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Target Content</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className={`w-full p-5 rounded-2xl flex justify-between items-center shadow-md transition-all group border-2 ${selectedCategories.length > 0 ? 'bg-slate-900 border-slate-900 text-white' : 'bg-white border-slate-200 text-slate-700 hover:border-blue-300'}`}
                   >
                      <div className="flex items-center gap-4">
                         <div className={`p-3 rounded-xl ${selectedCategories.length > 0 ? 'bg-white/10' : 'bg-slate-100'}`}>
                            <Settings2 size={20} className={selectedCategories.length > 0 ? 'text-white' : 'text-slate-500'} />
                         </div>
                         <div className="flex flex-col items-start">
                            <span className="font-black text-sm uppercase tracking-wide">
                               {selectedCategories.length === 0 ? "All Chapters" : "Custom Selection"}
                            </span>
                            <span className={`text-[10px] font-bold uppercase tracking-widest ${selectedCategories.length > 0 ? 'text-slate-400' : 'text-slate-400'}`}>
                               {selectedCategories.length === 0 ? "Default: Full Bank" : `${selectedCategories.length} Topics Active`}
                            </span>
                         </div>
                      </div>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${selectedCategories.length > 0 ? 'border-white/20 bg-white/10' : 'border-slate-100 bg-slate-50'}`}>
                         <ChevronRight size={14} />
                      </div>
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <ImageIcon size={14} /> Diagrams
                   </button>
                   <button 
                     onClick={() => setIsShuffle(!isShuffle)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                   >
                      <Shuffle size={14} /> Shuffle
                   </button>
                </div>

                {/* Start Button - Red */}
                <button 
                  onClick={startSession}
                  disabled={maxQuestions === 0}
                  className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-all active:scale-95 disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 group"
                >
                   {maxQuestions > 0 ? (
                     <>
                        Start Session <Play size={20} fill="currentColor" className="group-hover:translate-x-1 transition-transform" />
                     </>
                   ) : 'No Questions Found'}
                </button>

             </div>
          </div>
        </div>

        {/* Bank Selection Modal (Enhanced) */}
        {isBankModalOpen && (
          <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in">
             <div className="bg-white w-full max-w-lg h-[85vh] sm:h-auto max-h-[85vh] rounded-3xl overflow-hidden shadow-2xl flex flex-col animate-in slide-in-from-bottom-10">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                   <h3 className="font-bold text-slate-900">Select Chapters</h3>
                   <div className="flex gap-2">
                      <button onClick={() => setSelectedCategories(categories)} className="text-[10px] font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg hover:bg-rose-100">SELECT ALL</button>
                      <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg hover:bg-slate-200">CLEAR</button>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                   {categories.map(cat => {
                     const isSelected = selectedCategories.includes(cat);
                     return (
                       <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => 
                          prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
                        )}
                        className={`w-full p-5 rounded-2xl flex items-center justify-between transition-all duration-200 border-2 group active:scale-[0.98] ${isSelected ? 'border-emerald-500 bg-emerald-50/50 shadow-sm' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                       >
                          <span className={`font-bold text-left leading-tight ${isSelected ? 'text-emerald-900' : 'text-slate-600'}`}>{cat}</span>

                          {/* Enhanced Checkbox */}
                          <div className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center transition-all duration-300 ${isSelected ? 'border-emerald-500 bg-emerald-500 scale-110' : 'border-slate-200 bg-slate-50 group-hover:border-slate-300'}`}>
                             {isSelected && <Check size={16} className="text-white animate-in zoom-in duration-200" strokeWidth={4} />}
                          </div>
                       </button>
                     )
                   })}
                </div>
                <div className="p-4 border-t border-slate-100 bg-white shrink-0 pb-safe">
                   <button onClick={() => setIsBankModalOpen(false)} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-emerald-700 shadow-xl shadow-emerald-200 flex items-center justify-center gap-3 transition-transform active:scale-95">
                      <CheckCircle2 size={20} strokeWidth={3} />
                      <span>DONE</span>
                      <span className="bg-emerald-500/50 px-2 py-0.5 rounded text-xs">
                        {selectedCategories.length > 0 ? selectedCategories.length : 'All'}
                      </span>
                   </button>
                </div>
             </div>
          </div>
        )}
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            // In Practice mode, show Green for correct, Red for incorrect
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            // In Exam mode, just show answered state
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
              )}
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar with Progress */}
          <div className="bg-white border-b border-slate-200 px-4 md:px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20 relative overflow-hidden">

             {/* Progress Bar (The Step Visualization) */}
             <div className="absolute bottom-0 left-0 w-full h-1.5 bg-slate-100">
                <div 
                    className="h-full bg-rose-500 transition-all duration-500 ease-out relative"
                    style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                >
                    <div className="absolute right-0 top-0 bottom-0 w-2 bg-white/50 blur-[2px]"></div>
                </div>
             </div>

             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-3 md:gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> {isPracticeMode ? (mode === 'mistakes' ? 'Mistakes Review' : 'Practice Mode') : 'Anatomy Final'}
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' ? (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 md:px-4 md:py-2 rounded-lg border border-slate-200 ${timeLeft < 60 ? 'text-rose-600 bg-rose-50 border-rose-200 animate-pulse' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                ) : (
                    // In Practice mode, show score instead of timer
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                            <CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}
                        </div>
                        <div className="flex items-center gap-1.5 text-xs font-bold text-rose-600 bg-rose-50 px-3 py-1.5 rounded-lg border border-rose-100">
                            <XCircle size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}
                        </div>
                    </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-3 py-1.5 md:px-4 md:py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> <span className="hidden md:inline">Abort Exam</span><span className="md:hidden">Exit</span>
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc] pb-24 md:pb-20">
             <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
                {/* Question Card */}
                <div className="bg-white p-6 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className={`absolute top-0 left-0 w-full h-1.5 rounded-t-[1.5rem] ${isPracticeMode ? 'bg-indigo-500' : 'bg-blue-600'}`}></div>

                  <div className="flex justify-between items-start mb-6 md:mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-2xl md:text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="hidden md:inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-8 md:mb-10 flex flex-col md:flex-row md:items-start justify-between gap-4">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                     <button 
                        onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                        className={`p-2 rounded-full shrink-0 transition-colors self-end md:self-start ${isSpeaking ? 'bg-blue-100 text-blue-600 animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}
                     >
                        <Volume2 size={24} />
                     </button>
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-8 md:mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-4 md:p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[40vh] md:max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                            loading="eager"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       const isAnswered = !!currentQ.userAnswer;

                       let containerClasses = "bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50 text-slate-700";
                       let badgeClasses = "border-slate-200 text-slate-300 bg-white group-hover:border-slate-300";

                       if (isPracticeMode && isAnswered) {
                           // PRACTICE MODE LOGIC: Immediate Feedback
                           if (opt === currentQ.correctOption) {
                               // Correct Answer: Always Green
                               containerClasses = "bg-emerald-50 border-emerald-500 text-emerald-800 shadow-sm";
                               badgeClasses = "border-emerald-500 bg-emerald-500 text-white";
                           } else if (isSelected && opt !== currentQ.correctOption) {
                               // Wrong Selection: Red
                               containerClasses = "bg-rose-50 border-rose-500 text-rose-800 shadow-sm opacity-100";
                               badgeClasses = "border-rose-500 bg-rose-500 text-white";
                           } else {
                               // Other irrelevant options: Fade out
                               containerClasses = "bg-slate-50 border-slate-100 text-slate-400 opacity-50";
                           }
                       } else {
                           // EXAM MODE LOGIC: Standard Blue Selection
                           if (isSelected) {
                               containerClasses = "border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500 text-blue-900";
                               badgeClasses = "border-blue-500 bg-blue-600 text-white";
                           }
                       }

                       return (
                         <button 
                          key={i} 
                          onClick={() => {
                              if (isPracticeMode && isAnswered) return; // Prevent changing answer in practice mode
                              setQuestions(prev => { 
                                  const c = [...prev]; 
                                  c[currentQIndex].userAnswer = opt; 
                                  return c; 
                              });
                          }} 
                          disabled={isPracticeMode && isAnswered}
                          className={`w-full text-left p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 md:gap-5 group ${containerClasses}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm transition-colors ${badgeClasses}`}>
                              {isPracticeMode && isAnswered && opt === currentQ.correctOption ? <Check size={16} strokeWidth={4} /> : 
                               isPracticeMode && isAnswered && isSelected && opt !== currentQ.correctOption ? <X size={16} strokeWidth={4} /> :
                               String.fromCharCode(65 + i)}
                           </div>
                           <span className="text-base font-medium leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>

                  {/* Immediate Explanation in Practice Mode */}
                  {isPracticeMode && currentQ.userAnswer && (
                      <div className="mt-8 pt-8 border-t border-slate-100 animate-in slide-in-from-bottom-2 fade-in duration-500">
                          <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-slate-50 border-slate-300'}`}>
                              <div className="flex items-center gap-3 mb-3">
                                  <div className={`p-2 rounded-lg ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                                      <Zap size={18} fill="currentColor" />
                                  </div>
                                  <h4 className={`font-black uppercase tracking-widest text-xs ${currentQ.userAnswer === currentQ.correctOption ? 'text-emerald-700' : 'text-slate-600'}`}>
                                      {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                  </h4>
                              </div>
                              <p className="text-slate-700 font-medium leading-relaxed">
                                  {currentQ.data.explanation || "No detailed explanation is available for this record."}
                              </p>
                          </div>
                      </div>
                  )}

                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] pb-safe">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-4 md:px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span>
             </button>

             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                Q {currentQIndex + 1} / {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-6 md:px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Finish' : 'Next'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50 pb-safe overflow-y-auto custom-scrollbar">
        <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500 my-auto">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3 pt-6">
             <button onClick={() => setView('setup')} className="col-span-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="col-span-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review</button>

             {hasMistakes && (
               <button 
                 onClick={handleRetakeMistakes}
                 className="col-span-2 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1 flex items-center justify-center gap-2"
               >
                 <RotateCcw size={16} /> Retake Mistakes Immediately
               </button>
             )}
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-4 md:p-8 overflow-y-auto custom-scrollbar pb-safe">
        <div className="max-w-4xl mx-auto space-y-6 pb-20">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-6 md:p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 md:max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-0 md:pl-10 space-y-2 text-sm">
                 <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-slate-50 gap-2">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex flex-col md:flex-row md:justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100 gap-2">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

