                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) {
                        if (isPracticeMode) {
                            statusColor = q.userAnswer === q.correctOption 
                                ? "bg-emerald-100 border-emerald-300 text-emerald-700" 
                                : "bg-rose-100 border-rose-300 text-rose-700";
                        } else {
                            statusColor = "bg-slate-100 border-slate-300 text-slate-700";
                        }
                   }

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3 pb-safe">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              {isPracticeMode && (
                  <>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-emerald-400 rounded"></div> Correct
                    </div>
                    <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                        <div className="w-3 h-3 bg-rose-400 rounded"></div> Incorrect
                    </div>
                  </>
